func (m personalAccessTokenMods) WithParentsCascading() PersonalAccessTokenMod {
	return PersonalAccessTokenModFunc(func(ctx context.Context, o *PersonalAccessTokenTemplate) {
		if isDone, _ := personalAccessTokenWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = personalAccessTokenWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewOrganizationWithContext(ctx, OrganizationMods.WithParentsCascading())
			m.WithOrganization(related).Apply(ctx, o)
		}
		{

			related := o.f.NewUserAccountWithContext(ctx, UserAccountMods.WithParentsCascading())
			m.WithCreatedByUserAccount(related).Apply(ctx, o)
		}
		{

			related := o.f.NewUserAccountWithContext(ctx, UserAccountMods.WithParentsCascading())
			m.WithUpdatedByUserAccount(related).Apply(ctx, o)
		}
	})
}

